//                  cmake/cl2cpp.cmake; content is #ifdef HAVE_OPENCL-guarded
//                  and inert in this profile, kept byte-faithful anyway)
//   3. tu stubs  — ONLY for the libjpeg-turbo BITS_IN_JSAMPLE=12/16
